  "sites_vitrines.hero.title": "Showcase website designer in <span>Auch</span>: design, SEO &amp; performance",
  "sites_vitrines.hero.text": "Freelance web in <strong>Auch</strong> and the <strong>Gers</strong>: elegant, fast showcase sites optimized for <strong>local search ranking</strong>, contact generation and online credibility.",
  "sites_vitrines.hero.cta": "Talk about your project",

  "sites_vitrines.services.title": "Showcase sites designed to convince",
  "sites_vitrines.services.design.title": "Immersive design",
  "sites_vitrines.services.design.text": "Custom design aligned with your brand image for a strong, memorable first impression.",
  "sites_vitrines.services.seo.title": "Local SEO",
  "sites_vitrines.services.seo.text": "Clean structure optimized to be understood by Google and found by future clients.",
  "sites_vitrines.services.animations.title": "Advanced animations",
  "sites_vitrines.services.animations.text": "Light, elegant animations that add rhythm without hurting performance or readability.",
